1	use axum::{
2	    extract::{Request, State},
3	    http::{header, HeaderMap},
4	    middleware::Next,
5	    response::Response,
6	};
7	use chrono::Utc;
8	use sqlx::Row;
9	
10	use crate::{
11	    app::AppState,
12	    db,
13	    error::AppError,
14	    models::CurrentUser,
15	    security,
16	};
17	
18	pub const SESSION_COOKIE: &str = "depotcycle_session";
19	
20	pub async fn session_middleware(
21	    State(state): State<AppState>,
22	    mut request: Request,
23	    next: Next,
24	) -> Result<Response, AppError> {
25	    request.extensions_mut().insert::<Option<CurrentUser>>(None);
26	    let token = extract_cookie_token(request.headers());
27	
28	    if let Some(token) = token {
29	        let token_hash = security::sha256_hex(token.as_bytes());
30	        let row = sqlx::query(
31	            "SELECT s.id as session_id, u.id as user_id, u.username, r.name as role_name, s.expires_at
32	             FROM sessions s
33	             JOIN users u ON u.id = s.user_id
34	             JOIN roles r ON r.id = u.role_id
35	             WHERE s.token_hash = ?",
36	        )
37	        .bind(token_hash)
38	        .fetch_optional(&state.pool)
39	        .await?;
40	
41	        if let Some(row) = row {
42	            let expires_at: String = row.get("expires_at");
43	            let expires = chrono::DateTime::parse_from_rfc3339(&expires_at)
44	                .map_err(|_| AppError::internal("invalid session expiry"))?
45	                .with_timezone(&Utc);
46	
47	            if expires > Utc::now() {
48	                let session_id: String = row.get("session_id");
49	                db::touch_session(
50	                    &state.pool,
51	                    &session_id,
52	                    state.config.session_idle_timeout_minutes,
53	                )
54	                .await?;
55	
56	                request.extensions_mut().insert::<Option<CurrentUser>>(Some(CurrentUser {
57	                    id: row.get("user_id"),
58	                    username: row.get("username"),
59	                    role_name: row.get("role_name"),
60	                    session_id: Some(session_id),
61	                }));
62	            }
63	        }
64	    }
65	
66	    Ok(next.run(request).await)
67	}
68	
69	pub fn extract_cookie_token(headers: &HeaderMap) -> Option<String> {
70	    let cookie_header = headers.get(header::COOKIE)?.to_str().ok()?;
71	    for pair in cookie_header.split(';') {
72	        let mut parts = pair.trim().splitn(2, '=');
73	        let name = parts.next()?.trim();
74	        let value = parts.next()?.trim();
75	        if name == SESSION_COOKIE {
76	            return Some(value.to_string());
77	        }
78	    }
79	    None
80	}
81	
82	pub fn require_user(current_user: Option<CurrentUser>) -> Result<CurrentUser, AppError> {
83	    current_user.ok_or_else(|| AppError::unauthorized("authentication required"))
84	}
85	
86	pub fn require_admin(current_user: Option<CurrentUser>) -> Result<CurrentUser, AppError> {
87	    let user = require_user(current_user)?;
88	    if user.role_name != "Administrator" {
89	        return Err(AppError::forbidden("administrator access required"));
90	    }
91	    Ok(user)
92	}
