1	use axum::{
2	    http::StatusCode,
3	    response::{IntoResponse, Response},
4	    Json,
5	};
6	use serde::Serialize;
7	use tracing::error;
8	
9	#[derive(Debug)]
10	pub struct AppError {
11	    pub status: StatusCode,
12	    pub message: String,
13	}
14	
15	#[derive(Serialize)]
16	struct ErrorBody {
17	    error: String,
18	}
19	
20	impl AppError {
21	    pub fn new(status: StatusCode, message: impl Into<String>) -> Self {
22	        Self {
23	            status,
24	            message: message.into(),
25	        }
26	    }
27	
28	    pub fn bad_request(message: impl Into<String>) -> Self {
29	        Self::new(StatusCode::BAD_REQUEST, message)
30	    }
31	
32	    pub fn unauthorized(message: impl Into<String>) -> Self {
33	        Self::new(StatusCode::UNAUTHORIZED, message)
34	    }
35	
36	    pub fn forbidden(message: impl Into<String>) -> Self {
37	        Self::new(StatusCode::FORBIDDEN, message)
38	    }
39	
40	    pub fn not_found(message: impl Into<String>) -> Self {
41	        Self::new(StatusCode::NOT_FOUND, message)
42	    }
43	
44	    pub fn locked(message: impl Into<String>) -> Self {
45	        Self::new(StatusCode::LOCKED, message)
46	    }
47	
48	    pub fn internal(message: impl Into<String>) -> Self {
49	        Self::new(StatusCode::INTERNAL_SERVER_ERROR, message)
50	    }
51	}
52	
53	impl IntoResponse for AppError {
54	    fn into_response(self) -> Response {
55	        (self.status, Json(ErrorBody { error: self.message })).into_response()
56	    }
57	}
58	
59	impl From<sqlx::Error> for AppError {
